import React from "react";
import { motion, useAnimation } from "framer-motion";
import { useInView } from "react-intersection-observer";

const About = (props) => {
  const controls = useAnimation();
  const [ref, inView] = useInView({ threshold: 0.3 });

  React.useEffect(() => {
    if (inView) {
      controls.start("visible");
    } else {
      controls.start("hidden");
    }
  }, [inView, controls]);

  let sectionName, hello, about;
  if (props.resumeBasicInfo) {
    sectionName = props.resumeBasicInfo.section_name.about;
    hello = props.resumeBasicInfo.description_header;
    about = props.resumeBasicInfo.description;
  }

  // Define entry animations (no hover effects here)
  const variants = {
    hidden: { opacity: 0, y: 50, scale: 0.98 },
    visible: { 
      opacity: 1, 
      y: 0, 
      scale: 1,
      transition: { duration: 0.8, ease: "easeOut" }
    }
  };

  return (
    <section id="about" ref={ref} style={{ overflow: "hidden", paddingBottom: "100px" }}>
      <div className="col-md-12">
        {/* Animated Section Title */}
        <motion.h1
          style={{ color: "black", textAlign: "center", fontWeight: "bold" }}
          initial="hidden"
          animate={controls}
          variants={{
            hidden: { opacity: 0, letterSpacing: "-5px" },
            visible: { opacity: 1, letterSpacing: "3px", transition: { duration: 1 } }
          }}
        >
          <span>{sectionName}</span>
        </motion.h1>

        <div className="row center mx-auto mb-5">
          <div className="col-md-8 mx-auto" style={{ position: "relative" }}>

            {/* The Main Card - Movement removed */}
            <motion.div
              className="card"
              initial="hidden"
              animate={controls}
              variants={variants}
              style={{
                background: "white",
                borderRadius: "15px",
                border: "none",
                boxShadow: "0px 10px 30px rgba(0,0,0,0.08)", // Static shadow instead of hover shadow
                zIndex: 1
              }}
            >
              {/* Terminal Header */}
              <div className="card-header" style={{ background: "#f1f1f1", borderTopLeftRadius: "15px", borderTopRightRadius: "15px" }}>
                <span className="iconify" data-icon="emojione:red-circle"></span>
                &nbsp;
                <span className="iconify" data-icon="twemoji:yellow-circle"></span>
                &nbsp;
                <span className="iconify" data-icon="twemoji:green-circle"></span>
              </div>

              {/* Card Body with staggered text reveal */}
              <div
                className="card-body font-trebuchet text-justify ml-3 mr-3"
                style={{
                  height: "auto",
                  fontSize: "132%",
                  lineHeight: "180%",
                  paddingBottom: "40px",
                  color: "#333"
                }}
              >
                <motion.div
                  initial={{ opacity: 0, x: -20 }}
                  animate={inView ? { opacity: 1, x: 0 } : { opacity: 0, x: -20 }}
                  transition={{ delay: 0.4, duration: 0.6 }}
                >
                  <br />
                  <span className="wave" style={{ fontSize: "1.5rem", fontWeight: "bold" }}>
                    {hello} <motion.span 
                      animate={{ rotate: [0, 20, 0] }} 
                      transition={{ repeat: Infinity, duration: 1.5 }}
                      style={{ display: "inline-block" }}
                    >👋</motion.span>
                  </span>
                </motion.div>

                <motion.div
                  initial={{ opacity: 0 }}
                  animate={inView ? { opacity: 1 } : { opacity: 0 }}
                  transition={{ delay: 0.8, duration: 1 }}
                  style={{ marginTop: "20px" }}
                >
                  {about}
                </motion.div>
              </div>
            </motion.div>

            {/* Pulsing Backdrop Decoration */}
            <motion.div 
              style={{
                position: "absolute",
                width: "100%",
                height: "100%",
                background: "linear-gradient(45deg, #e9d5a1, #baaa80)",
                zIndex: -1,
                top: "15px",
                left: "15px",
                borderRadius: "15px",
                opacity: 0.2
              }}
              animate={inView ? { scale: [1, 1.02, 1], opacity: [0.1, 0.15, 0.1] } : {}}
              transition={{ repeat: Infinity, duration: 4 }}
            />
          </div>
        </div>
      </div>
    </section>
  );
};

export default About;
